import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom'; // Dùng để chuyển hướng
import { useMusic } from '../../context/MusicContext';
import { 
  Heart, ListPlus, Play, Music, CheckCircle2, 
  Circle, X, Library, ChevronRight 
} from 'lucide-react';

const Home = () => {
  const navigate = useNavigate(); // Khởi tạo điều hướng
  const [songs, setSongs] = useState([]);
  const [playlists, setPlaylists] = useState([]); // State lưu danh sách Playlist
  const { playMusic, currentSong } = useMusic();
  
  const [isSelecting, setIsSelecting] = useState(false);
  const [newPlaylistTitle, setNewPlaylistTitle] = useState("");
  const [selectedSongIds, setSelectedSongIds] = useState([]);

  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchSongs();
    if (loggedInUser) {
      fetchUserPlaylists();
    }
  }, []);

  // 1. Lấy tất cả bài hát
  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) { console.error("Lỗi tải nhạc:", err); }
  };

  // 2. Lấy danh sách Playlist của User (Để hiển thị và chuyển hướng)
  const fetchUserPlaylists = async () => {
    try {
      const userId = loggedInUser._id || loggedInUser.id;
      const res = await axios.get(`http://localhost:5000/api/playlists/user/${userId}`);
      setPlaylists(res.data);
    } catch (err) { console.error("Lỗi tải playlist:", err); }
  };

  const handleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    try {
      const res = await axios.post(`http://localhost:5000/api/songs/like/${songId}`, {
        userId: loggedInUser._id || loggedInUser.id
      });
      setSongs(songs.map(s => s._id === songId ? res.data : s));
    } catch (err) { console.error(err); }
  };

  const handleStartCreatePlaylist = () => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    const title = prompt("Nhập tên cho Playlist mới tại IAMNHAC:");
    if (!title) return;
    setNewPlaylistTitle(title);
    setIsSelecting(true);
    setSelectedSongIds([]);
  };

  const handleSavePlaylist = async () => {
    if (selectedSongIds.length === 0) {
      if (!window.confirm("Bạn chưa chọn bài hát nào. Vẫn muốn tạo playlist trống?")) return;
    }
    try {
      await axios.post('http://localhost:5000/api/songs/playlists', {
        title: newPlaylistTitle,
        userId: loggedInUser._id || loggedInUser.id,
        songIds: selectedSongIds
      });
      alert(`Thành công! Playlist "${newPlaylistTitle}" đã sẵn sàng.`);
      setIsSelecting(false);
      fetchUserPlaylists(); // Tải lại danh sách playlist sau khi tạo
    } catch (err) { alert("Lỗi khi lưu Playlist."); }
  };

  const handlePlaySong = (index) => {
    if (isSelecting) {
      const songId = songs[index]._id;
      setSelectedSongIds(prev => 
        prev.includes(songId) ? prev.filter(id => id !== songId) : [...prev, songId]
      );
    } else {
      playMusic(songs, index);
    }
  };

  return (
    <div style={pageContainer}>
      
      {/* SELECTION BAR (Khi tạo playlist) */}
      {isSelecting && (
        <div style={selectionBarStyle}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            <span>Đang chọn nhạc cho: <b style={{ color: '#1db954' }}>{newPlaylistTitle}</b></span>
            <span style={countBadge}>{selectedSongIds.length} bài đã chọn</span>
          </div>
          <div style={{ display: 'flex', gap: '15px' }}>
            <button onClick={handleSavePlaylist} style={btnSave}>HOÀN TẤT</button>
            <button onClick={() => setIsSelecting(false)} style={btnCancel}><X size={20} /></button>
          </div>
        </div>
      )}

      {/* HEADER */}
      <div style={headerStyle}>
        <h1 style={logoStyle}><Music size={36} /> IAMNHAC</h1>
        <button onClick={handleStartCreatePlaylist} style={btnPrimary}>
          <ListPlus size={18} strokeWidth={3} /> TẠO PLAYLIST MỚI
        </button>
      </div>

      {/* --- PHẦN 4 LÀM RÕ: HIỂN THỊ DANH SÁCH PLAYLIST VÀ CHUYỂN HƯỚNG --- */}
      {loggedInUser && playlists.length > 0 && !isSelecting && (
        <section style={{ marginBottom: '50px' }}>
          <div style={sectionTitleStyle}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <Library size={24} color="#1db954" />
              <h2 style={{ margin: 0 }}>Playlist của bạn</h2>
            </div>
          </div>
          
          <div style={playlistGrid}>
            {playlists.map((pl) => (
              <div 
                key={pl._id} 
                style={playlistCard} 
                onClick={() => navigate(`/playlist/${pl._id}`)} // CHUYỂN HƯỚNG TẠI ĐÂY
              >
                <div style={playlistIconBox}>
                  <Music size={40} color="#fff" />
                  <div style={playHoverIcon}><Play fill="#fff" size={24} /></div>
                </div>
                <h3 style={playlistTitle}>{pl.title}</h3>
                <p style={playlistSub}>{pl.songs?.length || 0} bài hát</p>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* GRID NHẠC TỔNG HỢP */}
      <section>
        <div style={sectionTitleStyle}>
          <h2 style={{ margin: 0 }}>Khám phá nhạc mới</h2>
        </div>
        <div style={songGridStyle}>
          {songs.map((song, index) => {
            const isSelected = selectedSongIds.includes(song._id);
            const isCurrentPlaying = currentSong?._id === song._id;
            
            return (
              <div 
                key={song._id} 
                style={{
                  ...songCard, 
                  border: isSelected ? '3px solid #1db954' : (isCurrentPlaying ? '3px solid #1db954' : 'none'),
                }}
                onClick={() => handlePlaySong(index)}
              >
                <div style={{ position: 'relative', overflow: 'hidden', borderRadius: '12px' }}>
                  <img src={`http://localhost:5000${song.imageUrl}`} alt={song.title} style={imgStyle} />
                  {isSelecting ? (
                     <div style={checkIconContainer}>
                       {isSelected ? <CheckCircle2 color="#1db954" fill="white" size={32}/> : <Circle color="#ccc" size={32}/>}
                     </div>
                  ) : (
                    <div style={playOverlayBtn}>
                      <Play fill="white" size={20} color="white" />
                    </div>
                  )}
                </div>
                <h3 style={songTitleText}>{song.title}</h3>
                <p style={artistText}>{song.artist}</p>
                
                {!isSelecting && (
                  <button onClick={(e) => { e.stopPropagation(); handleLike(song._id); }} style={likeBtnStyle}>
                      <Heart size={20} fill={song.likes?.includes(loggedInUser?._id) ? "red" : "none"} color={song.likes?.includes(loggedInUser?._id) ? "red" : "#666"} />
                      <span>{song.likes?.length || 0}</span>
                  </button>
                )}
              </div>
            );
          })}
        </div>
      </section>
    </div>
  );
};

/* --- STYLES --- */
const pageContainer = { padding: '30px', maxWidth: '1300px', margin: '0 auto', paddingBottom: '120px' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' };
const logoStyle = { color: '#1db954', margin: 0, display: 'flex', alignItems: 'center', gap: '10px', fontSize: '32px', fontWeight: '900' };
const sectionTitleStyle = { marginBottom: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };

// Playlist Styles
const playlistGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: '20px' };
const playlistCard = { background: '#181818', padding: '15px', borderRadius: '12px', cursor: 'pointer', transition: '0.3s', position: 'relative' };
const playlistIconBox = { width: '100%', aspectRatio: '1/1', background: '#282828', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '12px', position: 'relative', overflow: 'hidden' };
const playHoverIcon = { position: 'absolute', bottom: '10px', right: '10px', background: '#1db954', width: '40px', height: '40px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', opacity: 0, transition: '0.3s transform, 0.3s opacity', transform: 'translateY(10px)' };
// Hover effect cho card (thêm thủ công hoặc dùng CSS file)
// playlistCard:hover .playHoverIcon { opacity: 1; transform: translateY(0); }

const playlistTitle = { color: '#fff', fontSize: '16px', margin: '0 0 5px 0', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' };
const playlistSub = { color: '#b3b3b3', fontSize: '13px', margin: 0 };

// Song Styles
const songGridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '25px' };
const songCard = { background: '#fff', padding: '15px', borderRadius: '15px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', cursor: 'pointer', transition: '0.3s' };
const imgStyle = { width: '100%', aspectRatio: '1/1', objectFit: 'cover' };
const songTitleText = { margin: '12px 0 4px 0', fontSize: '16px', fontWeight: 'bold' };
const artistText = { color: '#666', fontSize: '13px', margin: '0 0 10px 0' };
const likeBtnStyle = { background: '#f9f9f9', border: 'none', padding: '5px 12px', borderRadius: '15px', display: 'flex', alignItems: 'center', gap: '6px', cursor: 'pointer' };

// Overlay & Floating Bars
const selectionBarStyle = { position: 'fixed', top: 0, left: 0, right: 0, height: '80px', backgroundColor: '#111', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 60px', zIndex: 2000, borderBottom: '2px solid #1db954' };
const playOverlayBtn = { position: 'absolute', bottom: '10px', right: '10px', background: '#1db954', borderRadius: '50%', width: '40px', height: '40px', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const checkIconContainer = { position: 'absolute', top: '10px', right: '10px' };
const countBadge = { background: '#333', padding: '5px 15px', borderRadius: '15px', fontSize: '14px', border: '1px solid #1db954' };
const btnSave = { background: '#1db954', color: 'white', border: 'none', padding: '10px 25px', borderRadius: '25px', fontWeight: 'bold', cursor: 'pointer' };
const btnCancel = { background: '#f44336', color: 'white', border: 'none', width: '35px', height: '35px', borderRadius: '50%', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const btnPrimary = { background: '#000', color: '#fff', border: 'none', padding: '10px 20px', borderRadius: '30px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };

export default Home;
